  1	import * as React from 'react';
  2	import {
  3	  LifecycleRule,
  4	  GetBucketLifecycleConfigurationCommandOutput,
  5	  ExpirationStatus,
  6	  LifecycleRuleFilter,
  7	} from '@aws-sdk/client-s3';
  8	import {
  9	  S3Provider,
 10	  S3Context,
 11	} from '@odf/core/components/s3-browser/s3-context';
 12	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
 13	import { StatusBox } from '@odf/shared/generic/status-box';
 14	import { isNoLifecycleRuleError } from '@odf/shared/s3/utils';
 15	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 16	import { deepSortObject } from '@odf/shared/utils';
 17	import * as _ from 'lodash-es';
 18	import { murmur3 } from 'murmurhash-js';
 19	import { useNavigate, useParams } from 'react-router-dom-v5-compat';
 20	import useSWR from 'swr';
 21	import {
 22	  TextVariants,
 23	  Text,
 24	  TextContent,
 25	  Divider,
 26	  Button,
 27	  ButtonVariant,
 28	} from '@patternfly/react-core';
 29	import { BUCKET_LIFECYCLE_RULE_CACHE_KEY_SUFFIX } from '../../../constants';
 30	import { GeneralConfigAndFilters } from './GeneralConfigAndFilters';
 31	import {
 32	  ruleReducer,
 33	  ruleInitialState,
 34	  RuleActionType,
 35	  RuleState,
 36	  RuleScope,
 37	} from './reducer';
 38	import { RuleActions } from './RuleActions';
 39	import { useEditLifecycleRule } from './useEditLifecycleRule';
 40	import { isInvalidLifecycleRule } from './validations';
 41	
 42	type IsEditProp = { isEdit?: boolean };
 43	
 44	const getFilterConfig = (
 45	  conditionalFilters: RuleState['conditionalFilters']
 46	): LifecycleRuleFilter => {
 47	  const prefix = conditionalFilters.prefix;
 48	  const tags = conditionalFilters.objectTags;
 49	  const minObjectSize = conditionalFilters.minObjectSize;
 50	  const maxObjectSize = conditionalFilters.maxObjectSize;
 51	
 52	  const filtersWOTags = {
 53	    ...(!!prefix ? { Prefix: prefix } : {}),
 54	    ...(minObjectSize.isChecked
 55	      ? { ObjectSizeGreaterThan: minObjectSize.sizeInB }
 56	      : {}),
 57	    ...(maxObjectSize.isChecked
 58	      ? { ObjectSizeLessThan: maxObjectSize.sizeInB }
 59	      : {}),
 60	  };
 61	
 62	  let ruleFilters: LifecycleRuleFilter;
 63	  const filtersWOTagsLength = Object.keys(filtersWOTags).length;
 64	  if (filtersWOTagsLength > 1 || tags.length > 1) {
 65	    ruleFilters = {
 66	      And: { ...filtersWOTags, ...(!!tags.length ? { Tags: tags } : {}) },
 67	    };
 68	  } else if (filtersWOTagsLength === 1 && tags.length === 1) {
 69	    ruleFilters = { And: { ...filtersWOTags, Tags: tags } };
 70	  } else {
 71	    ruleFilters = {
 72	      ...filtersWOTags,
 73	      ...(!!tags.length ? { Tag: tags[0] } : {}),
 74	    } as LifecycleRuleFilter;
 75	  }
 76	
 77	  return ruleFilters;
 78	};
 79	
 80	const getRuleConfig = (state: RuleState): LifecycleRule => {
 81	  const deleteCurrent = state.actions.deleteCurrent;
 82	  const deleteExpiredMarkers = state.actions.deleteExpiredMarkers;
 83	  const conditionalFilters = state.conditionalFilters;
 84	  const deleteNonCurrent = state.actions.deleteNonCurrent;
 85	  const deleteIncompleteMultiparts = state.actions.deleteIncompleteMultiparts;
 86	
 87	  const expirationConfig = {
 88	    ...(deleteCurrent.isChecked ? { Days: deleteCurrent.days } : {}),
 89	    ...(deleteExpiredMarkers
 90	      ? { ExpiredObjectDeleteMarker: deleteExpiredMarkers }
 91	      : {}),
 92	  };
 93	  const nonCurrentConfig = {
 94	    ...(deleteNonCurrent.isChecked
 95	      ? { NoncurrentDays: deleteNonCurrent.days }
 96	      : {}),
 97	    ...(deleteNonCurrent.isChecked && !!deleteNonCurrent.retention
 98	      ? { NewerNoncurrentVersions: deleteNonCurrent.retention }
 99	      : {}),
100	  };
101	  const multipartConfig = {
102	    ...(deleteIncompleteMultiparts.isChecked
103	      ? { DaysAfterInitiation: deleteIncompleteMultiparts.days }
104	      : {}),
105	  };
106	
107	  return {
108	    ...(!_.isEmpty(expirationConfig) ? { Expiration: expirationConfig } : {}),
109	    ID: state.name,
110	    ...(state.scope === RuleScope.TARGETED
111	      ? { Filter: getFilterConfig(conditionalFilters) }
112	      : { Filter: { Prefix: '' } }), // omitting or empty "Filter" results in error, using `{ Prefix: '' }` as a workaround for "global" scope.
113	    Status: ExpirationStatus.Enabled,
114	    ...(!_.isEmpty(nonCurrentConfig)
115	      ? { NoncurrentVersionExpiration: nonCurrentConfig }
116	      : {}),
117	    ...(!_.isEmpty(multipartConfig)
118	      ? { AbortIncompleteMultipartUpload: multipartConfig }
119	      : {}),
120	  };
121	};
122	
123	const createNewRule = (
124	  state: RuleState,
125	  latestRules: GetBucketLifecycleConfigurationCommandOutput
126	) => {
127	  const currRules: LifecycleRule[] =
128	    latestRules?.Rules?.filter((rule) => rule.ID !== state.name) || [];
129	  const newRule: LifecycleRule = getRuleConfig(state);
130	
131	  return [...currRules, newRule];
132	};
133	
134	const updateExistingRule = (
135	  state: RuleState,
136	  latestRules: GetBucketLifecycleConfigurationCommandOutput,
137	  ruleName: string,
138	  ruleHash: string
139	) => {
140	  let filteredRules: LifecycleRule[];
141	  if (!!ruleName) {
142	    filteredRules =
143	      latestRules?.Rules?.filter(
144	        (rule) => rule.ID !== ruleName && rule.ID !== state.name
145	      ) || [];
146	  } else if (!!ruleHash) {
147	    // fallback if rule name (ID) is missing
148	    filteredRules =
149	      latestRules?.Rules?.filter(
150	        (rule) =>
151	          `${murmur3(JSON.stringify(deepSortObject(rule)))}` !== ruleHash &&
152	          rule.ID !== state.name
153	      ) || [];
154	  } else {
155	    filteredRules = latestRules?.Rules || [];
156	  }
157	  const updateRule: LifecycleRule = getRuleConfig(state);
158	
159	  return [...filteredRules, updateRule];
160	};
161	
162	const Header: React.FC<IsEditProp> = ({ isEdit }) => {
163	  const { t } = useCustomTranslation();
164	
165	  return (
166	    <>
167	      <TextContent>
168	        <Text component={TextVariants.h1}>
169	          {isEdit ? t('Edit lifecycle rule') : t('Create lifecycle rule')}
170	        </Text>
171	        <Text component={TextVariants.small}>
172	          {t(
173	            'To optimize the storage costs of your objects throughout their lifecycle, set up a lifecycle configuration. This configuration consists of a series of rules that determine the actions S3 takes on a specific group of objects.'
174	          )}
175	        </Text>
176	      </TextContent>
177	      <Divider className="pf-v6-u-my-lg" />
178	    </>
179	  );
180	};
181	
182	const CreateOrEditLifecycleRuleForm: React.FC<IsEditProp> = ({ isEdit }) => {
183	  const { t } = useCustomTranslation();
184	
185	  const { bucketName } = useParams();
186	  const navigate = useNavigate();
187	  const { s3Client } = React.useContext(S3Context);
188	
189	  const [inProgress, setInProgress] = React.useState<boolean>(false);
190	  const [putError, setPutError] = React.useState<Error>();
191	  const [state, dispatch] = React.useReducer(ruleReducer, ruleInitialState);
192	
193	  const {
194	    data,
195	    isLoading,
196	    error: getError,
197	    mutate,
198	  } = useSWR(
199	    `${s3Client.providerType}-${bucketName}-${BUCKET_LIFECYCLE_RULE_CACHE_KEY_SUFFIX}`,
200	    () => s3Client.getBucketLifecycleConfiguration({ Bucket: bucketName }),
201	    {
202	      shouldRetryOnError: false,
203	    }
204	  );
205	
206	  const noRuleExistsError = isNoLifecycleRuleError(getError);
207	  // in case of "noRuleExistsError" error, cache could still have older "data", hence clearing that.
208	  const existingRules = noRuleExistsError ? undefined : data;
209	
210	  const [ruleName, ruleHash] = useEditLifecycleRule({
211	    isEdit,
212	    existingRules,
213	    dispatch,
214	  });
215	
216	  const onSave = async (event) => {
217	    event.preventDefault();
218	    setInProgress(true);
219	
220	    if (isInvalidLifecycleRule(state, existingRules, isEdit, ruleName)) {
221	      dispatch({
222	        type: RuleActionType.TRIGGER_INLINE_VALIDATIONS,
223	        payload: true,
224	      });
225	      setInProgress(false);
226	    } else {
227	      try {
228	        let latestRules: GetBucketLifecycleConfigurationCommandOutput;
229	
230	        try {
231	          latestRules = await s3Client.getBucketLifecycleConfiguration({
232	            Bucket: bucketName,
233	          });
234	        } catch (err) {
235	          if (isNoLifecycleRuleError(err)) {
236	            latestRules = {
237	              Rules: [],
238	            } as GetBucketLifecycleConfigurationCommandOutput;
239	          } else {
240	            throw err;
241	          }
242	        }
243	
244	        await s3Client.putBucketLifecycleConfiguration({
245	          Bucket: bucketName,
246	          LifecycleConfiguration: {
247	            Rules: isEdit
248	              ? updateExistingRule(state, latestRules, ruleName, ruleHash)
249	              : createNewRule(state, latestRules),
250	          },
251	        });
252	
253	        setInProgress(false);
254	        mutate();
255	        navigate(-1);
256	      } catch (err) {
257	        setInProgress(false);
258	        setPutError(err);
259	      }
260	    }
261	  };
262	
263	  if (isLoading || (getError && !noRuleExistsError)) {
264	    return (
265	      <StatusBox loaded={!isLoading} loadError={isLoading ? '' : getError} />
266	    );
267	  }
268	
269	  return (
270	    <div className="pf-v6-u-m-md">
271	      <Header isEdit={isEdit} />
272	      <GeneralConfigAndFilters
273	        state={state}
274	        dispatch={dispatch}
275	        existingRules={existingRules}
276	        isEdit={isEdit}
277	        editingRuleName={ruleName}
278	      />
279	      <RuleActions state={state} dispatch={dispatch} />
280	      <ButtonBar
281	        inProgress={inProgress}
282	        errorMessage={putError?.message || JSON.stringify(putError)}
283	        className="pf-v6-u-mt-lg pf-v6-u-mb-md"
284	      >
285	        <span>
286	          <Button
287	            variant={ButtonVariant.primary}
288	            onClick={onSave}
289	            isDisabled={inProgress}
290	            className="pf-v6-u-mr-xs"
291	          >
292	            {isEdit ? t('Save') : t('Create')}
293	          </Button>
294	          <Button
295	            variant={ButtonVariant.secondary}
296	            onClick={() => navigate(-1)}
297	            className="pf-v6-u-ml-xs"
298	          >
299	            {t('Cancel')}
300	          </Button>
301	        </span>
302	      </ButtonBar>
303	    </div>
304	  );
305	};
306	
307	export const CreateLifecycleRule: React.FC<{}> = () => (
308	  <S3Provider>
309	    <CreateOrEditLifecycleRuleForm />
310	  </S3Provider>
311	);
312	
313	export const EditLifecycleRule: React.FC<{}> = () => (
314	  <S3Provider>
315	    <CreateOrEditLifecycleRuleForm isEdit />
316	  </S3Provider>
317	);

